"""
MKT Christ Layer — Proverbs chapters 10–12
Run: python3 scripts/zc-christ-proverbs-10-12.py

Ch10: Solomonic antithetical proverbs begin; wise son / foolish son (10:1);
      mouth of righteous as fountain of life (10:11); love covers sins (10:12);
      righteous stands forever (10:25); tongue of righteous as choice silver (10:20)
Ch11: Honest scales (11:1); righteousness delivers from death (11:4);
      tree of life / wins souls (11:30); free giving increases (11:24-25)
Ch12: Path of righteousness = life, no death (12:28); truthful witness (12:17);
      healing tongue (12:18); Christ as the fully righteous man throughout
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DATA = {
  "10": {
    "1": "<p><b>Type / Theme.</b> <em>A wise son makes a glad father</em> — the father-son relationship as the structural frame of the entire Solomonic collection. The son who receives and embodies wisdom delights the father; the fool grieves him. Christ is the Son who <em>always</em> does what pleases the Father (John 8:29): at his baptism the Father declares his delight (<em>this is my beloved Son in whom I am well pleased</em>, Matt 3:17). Every human son who has grieved his father is repositioned in Christ — the Son who perfectly delighted the Father, whose record of filial faithfulness is imputed to the penitent who trusts him.</p>",
    "2": "<p><b>Theme.</b> <em>Treasures gained by wickedness do not profit, but righteousness delivers from death</em> — righteousness as the instrument of deliverance from death. The verse anticipates the doctrine of imputed righteousness: Paul argues in Romans that the righteousness credited to Abraham through faith (Rom 4:3-5) is the same righteousness that delivers from death (Rom 5:9). Christ's righteousness is the only righteousness that actually delivers from the death the verse has in view — the wickedness-gained treasure perishes; the righteousness that delivers is received, not achieved.</p>",
    "3": "<p><b>Revelation of God.</b> <em>The LORD does not let the righteous go hungry, but he thwarts the craving of the wicked</em> — the divine provision-pattern. Christ demonstrates this principle at the feeding of the five thousand (Matt 14:13-21) and in the Sermon on the Mount's promise that those who seek the kingdom will have <em>all these things added</em> (Matt 6:33). The LORD who does not let the righteous hunger is Christ who multiplies bread and who declares himself the Bread of Life (John 6:35) — the hunger Proverbs promises God will satisfy is met in him both physically and ultimately.</p>",
    "4": "<p><b>Theme.</b> <em>A slack hand causes poverty, but the hand of the diligent makes rich</em> — the work-ethic observation. While a general wisdom principle, the NT applies it christologically: Paul's instruction to work with one's hands (1 Thess 4:11; Eph 4:28) is grounded in the pattern that diligence produces the resources that enable generosity toward others. Christ the carpenter-craftsman (Mark 6:3) embodies dignified manual labor before his public ministry — the diligent hand as the normal human mode of sustaining life before the extraordinary calling comes.</p>",
    "5": "<p><b>Theme.</b> <em>He who gathers in summer is a prudent son, but he who sleeps in harvest is a son who brings shame</em> — the harvest-season wisdom. The harvest as a figure for the eschatological moment of gathering recurs throughout the Gospels: Christ declares the harvest is plentiful (Matt 9:37-38), commands his disciples to pray for workers, and uses the harvest as the figure of final judgment (Matt 13:30, 39). The son who gathers in summer is the disciple who responds to the harvest-urgency Christ identifies; the sleeping son is the one who misses the appointed moment.</p>",
    "6": "<p><b>Theme.</b> <em>Blessings are on the head of the righteous, but the mouth of the wicked conceals violence</em> — the beatitude-pattern of blessing on the righteous. The Sermon on the Mount's beatitudes (Matt 5:3-12) are the NT form of this sapience observation — the righteousness of the kingdom-seeker attracts divine blessing. Christ's own head received a crown of thorns — the blessings that should rest on the head of the perfectly righteous one were momentarily replaced by the marks of the wicked's violence, absorbing what the second half of the verse identifies as the wicked's characteristic covering.</p>",
    "7": "<p><b>Revelation of God.</b> <em>The memory of the righteous is a blessing, but the name of the wicked will rot</em> — the name-memory principle. Christ's name is the name above every name (Phil 2:9-10), the name by which people are saved (Acts 4:12), the name that endures into eternity (Rev 19:13). The righteous whose memory is a blessing are those who bear his name in faithfulness. The wicked whose name rots is the countertype — those whose earthly prominence dissolves against the permanence of Christ's name.</p>",
    "8": "<p><b>Theme.</b> <em>The wise of heart will receive commandments, but a babbling fool will come to ruin</em> — receptivity to instruction as wisdom's mark. Christ's disciples are characterized precisely by this receptivity — they receive the commands Christ gives (John 14:21; 15:10) and keep them as the expression of love for the Father. The fool who babbles (<em>eiwelet sefatayim</em>, lips of folly) contrasts with the wise heart that is oriented to receive rather than to produce undiscriminated speech.</p>",
    "9": "<p><b>Type.</b> <em>Whoever walks in integrity walks securely, but he who makes his ways crooked will be found out</em> — integrity of walk as the path of security. Christ is the Way (John 14:6) — the one in whom the crooked-or-straight choice of Proverbs is resolved. The straight path is not merely a moral posture but a Person: those who walk in him walk in integrity because they walk in the one who is himself truth. The one who makes crooked ways will be <em>found out</em> — at the judgment, all concealment ends, which is precisely why the only security is union with the one whose walk was always straight.</p>",
    "10": "<p><b>Theme.</b> <em>Whoever winks the eye causes trouble, and a babbling fool will come to ruin</em> — the deceptive wink as a social harm. Judas's betrayal-signal at the Last Supper (the gesture of identifying Jesus to his captors) is the ultimate expression of the deceptive communication this proverb warns against — the surface warmth concealing betrayal. Christ himself warned that those who say <em>Lord, Lord</em> but do not do his will will be revealed (Matt 7:21-23) — the babbling fool's surface religiosity concealing an absence of genuine relationship.</p>",
    "11": "<p><b>Type.</b> <em>The mouth of the righteous is a fountain of life, but the mouth of the wicked conceals violence</em> — the <em>mekor chayim</em> (fountain of life) produced by the righteous man's speech. Christ declares: <em>Whoever believes in me, as the Scripture has said, rivers of living water will flow from his heart</em> (John 7:38). The righteous man of Proverbs 10:11 who produces life-giving speech is a type pointing to Christ, in whom the fountain of life is not merely verbal but ontological — his Spirit poured out is the living water that springs up to eternal life (John 4:14).</p>",
    "12": "<p><b>Theme.</b> <em>Hatred stirs up strife, but love covers all offenses</em> — the <em>covers-offenses</em> principle that Peter quotes directly (1 Pet 4:8: <em>love covers a multitude of sins</em>). The ultimate expression of love covering offenses is the atonement: Christ's death covers the sins of those who trust him, not by ignoring them but by bearing them. The love that covers is not sentimental tolerance but the absorptive capacity of the one who takes the offense into himself. John's Gospel makes this explicit: the greater love of laying down one's life (John 15:13) is the maximum form of what Proverbs 10:12 describes.</p>",
    "13": "<p><b>Theme.</b> <em>On the lips of him who has understanding, wisdom is found, but a rod is for the back of him who lacks sense</em> — wisdom on the lips as the mark of understanding. Christ's teaching is consistently described as having authority (<em>exousia</em>) unlike the scribes (Matt 7:29) — wisdom resident in his lips that comes from the divine source directly. James identifies the tongue as the test of the religious life (Jas 3:2-12), making the wisdom-or-rod principle of Proverbs applicable to the character of speech that marks those formed by Christ's instruction.</p>",
    "14": "<p><b>Theme.</b> <em>The wise lay up knowledge, but the mouth of a fool brings ruin near</em> — storing vs. expending knowledge. The disciples' instruction is described as <em>storing up</em> in Matthew 13:52: the scribe trained for the kingdom <em>brings out of his treasure what is new and what is old</em>. Christ is himself the storehouse of <em>all the treasures of wisdom and knowledge</em> (Col 2:3) — the wise man who lays up knowledge is the one in communion with the one in whom all knowledge is hid, rather than producing from his own unreliable resources.</p>",
    "15": "<p><b>Theme.</b> <em>A rich man's wealth is his strong city; the poverty of the poor is their ruin</em> — the economic-security observation. Christ's parable of the rich fool (Luke 12:16-21) is the NT deconstruction of this observation: the strong city of wealth is shown to be no city at all on the night when the soul is required. The observation is sociologically accurate but spiritually incomplete — Proverbs itself offers the corrective in 18:10-11 (the name of the LORD is the strong tower the righteous runs into). Christ is the strong tower that wealth pretends to be.</p>",
    "16": "<p><b>Theme.</b> <em>The wages of the righteous lead to life, the gain of the wicked to sin</em> — the eschatological direction of work's fruit. Paul's wage-metaphor for justification in Romans 4:4-5 contrasts the earned wage with the gift of righteousness — but within the category of earned wages, Proverbs' observation stands: what the righteous produce leads toward life. Christ's work — his perfect obedience — earned the wage of life (resurrection) that he shares with those united to him, while the wage of sin is death (Rom 6:23), the trajectory the wicked's gain follows.</p>",
    "17": "<p><b>Theme.</b> <em>Whoever heeds instruction is on the path of life, but he who rejects reproof leads others astray</em> — the instruction-path connection. Christ's instruction is the path of life in a direct sense: <em>the words I have spoken to you are spirit and life</em> (John 6:63). Heeding Christ's instruction is the NT form of what Proverbs identifies as the life-path. The one who rejects reproof leads others astray — the false teacher who misleads others is the maximum expression of this, and both 2 Pet 2 and Jude develop this warning in explicitly christological contexts.</p>",
    "18": "<p><b>Revelation of God.</b> <em>The one who conceals hatred has lying lips, and whoever utters slander is a fool</em> — the two forms of verbal wickedness: concealed hatred and open slander. Christ's diagnostic is sharper: hatred and slander are already murder in the heart's economy (Matt 5:21-22). He himself faced both — the concealed hatred of the Pharisees who sought to trap him while presenting as pious questioners, and the open slander that called him demon-possessed (John 8:48). His response to both was truth rather than retaliation.</p>",
    "19": "<p><b>Theme.</b> <em>When words are many, transgression is not lacking, but whoever restrains his lips is prudent</em> — the economy of speech. Christ's instruction extends this to oaths: <em>let your yes be yes and your no be no; anything more than this comes from evil</em> (Matt 5:37). The restraint of lips Proverbs commends is the speech-discipline of those formed by Christ's teaching — enough to be clear, no more than truth requires. James develops this in his sustained reflection on the tongue (Jas 3), which is essentially the NT commentary on this verse.</p>",
    "20": "<p><b>Type.</b> <em>The tongue of the righteous is choice silver; the heart of the wicked is of little worth</em> — choice silver as the figure for valuable, refined speech. The metallurgical image: silver that has been smelted pure. Christ's words are described as the words of eternal life (John 6:68) — the tongue of the perfectly righteous one produces speech of incomparable value. The silver-tongue type points to the one whose every word is proven true (Prov 30:5), whose speech creates and sustains life (John 1:3; 11:43).</p>",
    "21": "<p><b>Theme.</b> <em>The lips of the righteous feed many, but fools die for lack of sense</em> — the feeding-by-speech principle. Christ's feeding ministry operates at multiple levels simultaneously: physical bread and fish for thousands, and the word that is true food (John 4:32; 6:35). The righteous one whose lips feed many is fulfilled in the one who feeds the multitude and whose lips produce the bread-of-life discourse. Paul's ministry as feeding those he had led to faith (1 Cor 3:2; 1 Thess 2:7-8) is the apostolic extension of this pattern.</p>",
    "22": "<p><b>Revelation of God.</b> <em>The blessing of the LORD makes rich, and he adds no sorrow with it</em> — the sorrow-free blessing. The blessings human effort produces are mixed with the anxiety of maintenance and the grief of loss. Christ identifies the kingdom's gifts as the sorrow-free form: <em>my joy I give you, not as the world gives</em> (John 14:27; 15:11). The peace and joy that are fruits of the Spirit (Gal 5:22) are the NT form of the sorrow-free blessing Proverbs locates in the LORD's direct gift rather than in human accumulation.</p>",
    "23": "<p><b>Theme.</b> <em>Doing wrong is like a joke to a fool, but wisdom is pleasure to a man of understanding</em> — the affective register of wisdom vs. folly. The fool finds transgression amusing — he has no interior alarm that registers moral wrongness as serious. Christ's teaching on the heart (Matt 15:18-19) identifies this desensitization as the root problem: the hardened heart that produces evil is the heart that has lost the capacity for the moral seriousness Proverbs commends as pleasure in wisdom.</p>",
    "24": "<p><b>Theme.</b> <em>What the wicked dreads will come upon him, but the desire of the righteous will be granted</em> — the granted-desire of the righteous. Christ's promise extends this: <em>whatever you ask in my name, this I will do</em> (John 14:13-14). The desire-granted is not a blank check but the prayer of those whose desires are formed by communion with Christ — their requests align with the Father's will because they are shaped by the Son's character. The wicked's dread-coming-upon-him is the judgment-reversal pattern of the beatitudes (Matt 5:3-12).</p>",
    "25": "<p><b>Type / Theme.</b> <em>When the tempest passes, the wicked is no more, but the righteous is established forever</em> — the storm-survival formula. Christ's parable of the wise and foolish builders (Matt 7:24-27) applies exactly this principle: when the storm (<em>chevrona</em>) comes, the house built on rock (<em>tzur</em>) stands while the house built on sand collapses. The wise builder is the one who hears and does Christ's words — the righteous established forever is the one whose foundation is Christ himself. The storm is both historical pressure and eschatological judgment.</p>",
    "26": "<p><b>Theme.</b> <em>Like vinegar to the teeth and smoke to the eyes, so is the sluggard to those who send him</em> — the irritant-comparison. The disciples are sent (apostello) precisely to be reliable messengers (Matt 10:16; John 17:18). The irresponsible messenger is the antithesis of the apostolic pattern Christ establishes — the sent-one who fails the sending represents a relational and missional failure, not merely an inconvenience. Paul's anxiety about being disqualified from the race (1 Cor 9:27) is the apostolic form of this concern.</p>",
    "27": "<p><b>Theme.</b> <em>The fear of the LORD prolongs life, but the years of the wicked will be cut short</em> — longevity as the fruit of covenant faithfulness. Christ identifies himself as the resurrection and the life (John 11:25) — the one in whom the life-prolongation Proverbs promises to the God-fearer is ultimately secured, not merely extended. Eternal life is the maximum expression of what <em>prolonged life</em> points toward. The fear of the LORD that produces life is defined in John as knowing the Father and the Son (John 17:3).</p>",
    "28": "<p><b>Theme.</b> <em>The hope of the righteous brings joy, but the expectation of the wicked will perish</em> — hope as a defining mark of the righteous. Paul's theology of hope (Rom 5:1-5; 8:24-25) is grounded precisely in the resurrection of Christ: <em>we have this hope as an anchor for the soul</em> (Heb 6:19). The hope of the righteous brings joy because it is a settled orientation toward the certain future that God has secured in Christ's resurrection. The wicked's expectation perishes because it is grounded in present circumstances alone.</p>",
    "29": "<p><b>Revelation of God.</b> <em>The way of the LORD is a stronghold to the blameless, but destruction to evildoers</em> — the LORD's way as protection for the blameless and destruction for the wicked. The same object (God's revealed will/path) produces opposite effects depending on the person who encounters it. This double-effect pattern is the hermeneutic Paul uses for the gospel: <em>to one a fragrance from death to death, to the other a fragrance from life to life</em> (2 Cor 2:16). Christ's cross is the most concentrated expression of the LORD's way — it is both salvation and judgment depending on the orientation of the one who encounters it (John 3:17-19).</p>",
    "30": "<p><b>Theme.</b> <em>The righteous will never be removed, but the wicked will not dwell in the land</em> — the land-permanence of the righteous as covenant promise. Christ extends the land-promise to its eschatological scope: <em>the meek shall inherit the earth</em> (Matt 5:5, citing Ps 37:11). The removal of the wicked from the land is the eschatological judgment that separates the wheat from the chaff (Matt 13:30). The righteous who are never removed are those whose citizenship is in the new Jerusalem — the land-promise transformed into an eternal inheritance (Heb 11:14-16).</p>",
    "31": "<p><b>Type.</b> <em>The mouth of the righteous brings forth wisdom, but the perverse tongue will be cut off</em> — wisdom produced by the mouth of the righteous. The tree-fruit imagery (mouth bringing forth) and the cutting-off of the perverse tongue anticipates the vine-branch language of John 15: the branch that bears fruit remains; the one that does not is cut off and thrown into the fire (John 15:2, 6). Christ as the perfectly righteous one whose mouth produces wisdom is the Logos through whom all wisdom originates (Col 2:3) — and who cuts off what is perverse by the sword of his mouth (Rev 19:15).</p>",
    "32": "<p><b>Type.</b> <em>The lips of the righteous know what is acceptable, but the mouth of the wicked, what is perverse</em> — knowing what is acceptable to speak (ratzon, the LORD's good pleasure). Christ's speech is always characterized by its alignment with the Father's will: <em>I have not spoken on my own authority, but the Father who sent me has himself given me a commandment — what to say and what to speak</em> (John 12:49). The righteous man's lips that know what is acceptable are the type of the Son whose every word is the Father's word — the acceptable speech being the speech that is sourced in God rather than in the speaker's own inclinations.</p>"
  },
  "11": {
    "1": "<p><b>Revelation of God.</b> <em>A false balance is an abomination to the LORD, but a just weight is his delight</em> — the divine character revealed in commercial justice. The LORD who hates deceptive weights is the God of exact measure. In Christ, God's measure is fully revealed: the cross is the exact weight placed on the scales of justice — neither more nor less than what the debt of sin required. Christ himself is the just weight by which all things are measured (Rev 19:11 — <em>in righteousness he judges</em>). Every human economic injustice points toward the need for the one in whom God's exact justice is satisfied.</p>",
    "2": "<p><b>Theme.</b> <em>When pride comes, then comes disgrace, but with the humble is wisdom</em> — the pride-disgrace / humility-wisdom connection. The Philippians hymn (Phil 2:5-11) is the NT's most concentrated statement of this principle at the divine scale: the Son who did not count equality with God a thing to be grasped humbled himself to the point of death, and was therefore highly exalted. Christ's humiliation is both the demonstration of perfect wisdom and the ground for his exaltation — the proverb's pattern embodied maximally.</p>",
    "3": "<p><b>Theme.</b> <em>The integrity of the upright guides them, but the crookedness of the treacherous destroys them</em> — integrity as the navigator. Christ's prayer for his disciples' sanctification is that they be kept in God's name and in his truth (John 17:11, 17) — the truth that functions as the guide of the upright. The crookedness of the treacherous that destroys them is the internal inconsistency of a divided allegiance — the double-minded man of James 1:8 — and ultimately, the self-destruction of Judas, whose treachery (<em>begidim</em>, the treacherous) was precisely his crookedness.</p>",
    "4": "<p><b>Theme.</b> <em>Riches do not profit in the day of wrath, but righteousness delivers from death</em> — the wrath-day and righteousness as deliverance. Paul's argument in Romans 5:9: <em>we have been justified by his blood, much more shall we be saved by him from the wrath of God</em>. The righteousness that delivers from death on the day of wrath is Christ's righteousness credited to those who trust him. No wealth, status, or achievement survives the day of wrath — only the alien righteousness of the One who bore the wrath in the sinner's place delivers from what Proverbs identifies as the ultimate threat.</p>",
    "5": "<p><b>Type.</b> <em>The righteousness of the blameless keeps his way straight, but the wicked falls by his own wickedness</em> — straight-way through righteousness. Christ is the perfectly blameless one (<em>tamim</em>, whole, complete) whose way was kept straight through his entire life and through his death. The sin that trips the wicked and makes them fall by their own wickedness is the sin he bore without himself falling. The straight way he walked is the path now open to those in him — not because they walk it perfectly but because he walked it perfectly on their behalf.</p>",
    "6": "<p><b>Theme.</b> <em>The righteousness of the upright delivers them, but the treacherous are taken captive by their lust</em> — delivered righteousness vs. captive lust. The slavery-to-sin diagnosis of Romans 6:16-18 develops the captive-by-lust observation: <em>you are slaves to the one you obey</em>. Christ's liberation is the freedom from this captivity — <em>if the Son sets you free, you will be free indeed</em> (John 8:36). The delivery from captivity is not by willpower but by the righteousness that belongs to the upright through union with the one who embodies upright perfectly.</p>",
    "7": "<p><b>Theme.</b> <em>When the wicked dies, his hope perishes, and the expectation of wealth perishes too</em> — the death-ends-all reality for those whose hope is horizontal. Paul's argument in 1 Cor 15:19 describes the alternative: <em>if in Christ we have hope only in this life, we are of all people most to be pitied</em>. The wicked whose hope perishes at death is the one who has staked everything on this-world outcomes. Christ's resurrection is the ground of hope that does not perish at death — the counterpoint to the proverb's observation is the empty tomb.</p>",
    "8": "<p><b>Theme.</b> <em>The righteous is delivered from trouble, and the wicked walks into it instead</em> — the substitution pattern: trouble that was coming for the righteous arrives at the wicked. This is the normal providential pattern Proverbs observes; its inversion is the gospel: the trouble (wrath, judgment, death) that was coming for the wicked arrived at the righteous One who voluntarily entered the trouble to absorb it. Christ is the righteous one who walked into the trouble meant for others — the substitutionary logic the proverb observes at the social level becomes the atonement at the cosmic level.</p>",
    "9": "<p><b>Revelation of God.</b> <em>With his mouth the godless man would destroy his neighbor, but by knowledge the righteous are delivered</em> — destructive speech vs. knowledge-bearing speech as deliverance. The godless man whose mouth destroys is the false teacher who ruins those who trust him — the NT expands this to include false prophets (Matt 7:15; 2 Pet 2:1). The knowledge that delivers the righteous is ultimately the knowledge of Christ: <em>eternal life is knowing you, the only true God, and Jesus Christ whom you have sent</em> (John 17:3). The true knowledge is the counterpower to the destructive word.</p>",
    "10": "<p><b>Theme.</b> <em>When it goes well with the righteous, the city rejoices, and when the wicked perish there are shouts of gladness</em> — the community-affect of righteousness and wickedness. The city that rejoices at the righteous man's well-being anticipates the new Jerusalem where <em>God himself will be with them as their God</em> (Rev 21:3) and where joy is the defining atmosphere. The rejoicing at the wicked's perishing is the counterpart — the judgment that removes the oppressor is itself an occasion for communal joy (Rev 19:1-4, the heavenly rejoicing at Babylon's fall).</p>",
    "11": "<p><b>Theme.</b> <em>By the blessing of the upright a city is exalted, but by the mouth of the wicked it is overthrown</em> — the blessing of the upright as civic architecture. Abraham's intercession for Sodom (Gen 18:22-33) is the paradigmatic example: the upright man's blessing was the potential salvation of the city. Christ's intercession for the city — weeping over Jerusalem (Luke 19:41-44) and praying for his executioners (Luke 23:34) — is the maximum expression of the upright man whose blessing maintains the city. The mouth of the wicked that overthrows is the antithesis: the false prophets and corrupt leaders who dismantled Jerusalem.</p>",
    "12": "<p><b>Theme.</b> <em>Whoever belittles his neighbor lacks sense, but a man of understanding remains silent</em> — contempt vs. wise silence. The wise silence of understanding is the character of the one who does not use words to diminish others. Christ's silence before his accusers (Matt 26:63; 27:12-14) is the most striking embodiment of wise restraint — the man of understanding who remains silent when slander is poured out on him. His silence fulfills Isaiah 53:7: <em>he opened not his mouth</em> — the sheep before its shearers is dumb.</p>",
    "13": "<p><b>Theme.</b> <em>Whoever goes about slandering reveals secrets, but he who is trustworthy in spirit keeps a thing covered</em> — faithful discretion as a relational virtue. Christ's instruction about the treatment of a brother's sin (Matt 18:15-17) follows this principle: the private confrontation before any public disclosure reflects the trustworthy spirit that covers rather than exposes. John's Gospel consistently presents Christ as the one who knows all things about people (John 2:24-25; 4:17-18) but exercises that knowledge with perfect discretion — revealing only what serves the person's redemption.</p>",
    "14": "<p><b>Theme.</b> <em>Where there is no guidance, a people falls, but in an abundance of counselors there is safety</em> — counsel-plurality as a safeguard. The Spirit is given as Counselor (<em>Paraclete</em>, John 14:16, 26; 15:26; 16:7) — Christ explicitly provides the abundance of divine counsel through his Spirit's presence in the church. The Christ-formed community that takes decisions in the Spirit under the wisdom of multiple voices embodies what Proverbs identifies as the safety-producing condition. The council of advisors becomes the Spirit-filled assembly.</p>",
    "15": "<p><b>Theme.</b> <em>Whoever puts up security for a stranger will surely suffer harm, but he who hates striking hands in pledge is secure</em> — the financial-guaranty warning. The antitype: Christ stood surety for those who were his enemies — he who knew no sin was made sin for us (2 Cor 5:21). He is the guarantor (<em>engyos</em>, surety) of a better covenant (Heb 7:22). The wisdom tradition warns against reckless surety-pledge; the gospel announces that God in Christ took the ultimate surety — suffering the harm Proverbs warns against, on behalf of the strangers.</p>",
    "16": "<p><b>Theme.</b> <em>A gracious woman gets honor, and violent men get riches</em> — the gendered observation about honor-routes. The gracious woman of Proverbs is the wisdom-embodiment that the book consistently develops toward the eshet chayil of chapter 31. At the level of type, the gracious woman who receives honor is the type of the church — the bride of Christ (Rev 19:7-8; Eph 5:25-27) who is clothed with righteousness and receives the honor of union with the Lamb. Her honor comes through grace rather than violent grasping.</p>",
    "17": "<p><b>Revelation of God.</b> <em>A man who is kind benefits himself, but a cruel man hurts himself</em> — the self-directed benefit of kindness. The divine kindness (<em>chesed</em>) that characterizes God is the model for human kindness — <em>be kind to one another, tenderhearted, forgiving one another, as God in Christ forgave you</em> (Eph 4:32). Christ's kindness is simultaneously his own beatitude and the pattern for those united to him. The proverb's self-benefit is the paradox of the kingdom: the one who gives himself for others receives himself back; the cruel one who grasps loses even what he has.</p>",
    "18": "<p><b>Theme.</b> <em>The wicked earns deceptive wages, but one who sows righteousness gets a sure reward</em> — sowing righteousness for a sure reward. The harvest/sowing metaphor runs throughout NT ethics: <em>whoever sows to the Spirit will from the Spirit reap eternal life</em> (Gal 6:8). Christ is himself both the sower (Matt 13:37) and the seed sown (John 12:24) — the grain of wheat that falls into the earth and produces the harvest of many. The sure reward of righteousness-sowing is grounded in his resurrection as the firstfruits (1 Cor 15:20).</p>",
    "19": "<p><b>Theme.</b> <em>Whoever is steadfast in righteousness will live, but he who pursues evil will die</em> — the righteousness-life / evil-death equation. Romans 8:6 states the same principle in pneumatological terms: <em>to set the mind on the flesh is death, but to set the mind on the Spirit is life and peace</em>. The steadfast righteousness that produces life is not achieved through willpower but received through the Spirit — the life-producing direction of heart orientation being the same in both texts.</p>",
    "20": "<p><b>Revelation of God.</b> <em>Those of crooked heart are an abomination to the LORD, but those of blameless ways are his delight</em> — the divine delight in blamelessness. The Father's declaration over Christ — <em>this is my beloved Son in whom I am well pleased</em> (Matt 3:17; 17:5) — is the maximum expression of this divine delight. Those united to Christ participate in this delight: <em>he has made us accepted in the Beloved</em> (Eph 1:6). The blameless-ways-as-delight is the orientation of the justified community — their ways are not their own blamelessness but their participation in the Blameless One.</p>",
    "21": "<p><b>Theme.</b> <em>Be assured, an evil person will not go unpunished, but the offspring of the righteous will be delivered</em> — the sure punishment / sure deliverance. The certainty formula (<em>yad leyad</em>, hand to hand — a sealing gesture affirming the certainty) introduces both sides. The deliverance of the righteous offspring anticipates the resurrection community — those who bear the character of the righteous one. Christ's resurrection is the first instance of the offspring-of-righteousness being delivered; his people share this deliverance as co-heirs (Rom 8:17).</p>",
    "22": "<p><b>Theme.</b> <em>Like a gold ring in a pig's snout is a beautiful woman without discretion</em> — the incoherence between outward beauty and inner character. The reverse applies to the church as Christ's bride: not outwardly splendid but inwardly adorned — <em>the unfading beauty of a gentle and quiet spirit</em> (1 Pet 3:4). Paul's description of the church Christ presents to himself <em>without spot or wrinkle</em> (Eph 5:27) is the gold ring on the finger that belongs to it — discretion (inner character) and beauty (outward glory) in genuine correspondence, which only Christ can accomplish in his bride.</p>",
    "23": "<p><b>Theme.</b> <em>The desire of the righteous ends only in good, the expectation of the wicked in wrath</em> — the endpoint-of-desire formula. The beatitude: <em>blessed are those who hunger and thirst for righteousness, for they shall be satisfied</em> (Matt 5:6). The desire of the righteous that ends in good is the desire shaped by the kingdom's values — which Christ promises will be satisfied. The wrath that waits for the wicked's expectation is the day when all that horizontal hope meets the divine assessment.</p>",
    "24": "<p><b>Theme.</b> <em>One gives freely, yet grows all the richer; another withholds what he should give, and only suffers want</em> — the paradox of generous increase. John 12:24-25: <em>unless a grain of wheat falls into the earth and dies, it remains alone; but if it dies, it bears much fruit. Whoever loves his life loses it, and whoever hates his life in this world will keep it for eternal life</em>. The freely-giving-yet-growing-richer is the grain-of-wheat principle — the logic of the cross and resurrection. Christ is the first and foundational instance of the proverb's paradox.</p>",
    "25": "<p><b>Theme.</b> <em>Whoever brings blessing will be enriched, and one who waters will himself be watered</em> — the reciprocal watering principle. The fountain-of-water that becomes a spring within the one who gives is the Johannine promise: <em>the water I give will become in him a spring of water welling up to eternal life</em> (John 4:14). Those who give freely from what Christ gives do not deplete but increase — the water flowing through them from Christ replenishes what they pour out. The blesser-enriched principle is grounded in the inexhaustible source from which the blessing flows.</p>",
    "26": "<p><b>Theme.</b> <em>The people curse him who holds back grain, but a blessing is on the head of him who sells it</em> — the grain-sharing and community blessing. The feeding of the five thousand is the most direct enactment of the grain-sharing principle: Christ takes what is withheld by scarcity and distributes it freely, drawing the blessing of the crowd. More fundamentally, Christ is the Bread of Life (John 6:35) — the withheld grain of the world's hunger, freely distributed, is the figure of the one in whom all spiritual hunger is satisfied.</p>",
    "27": "<p><b>Revelation of God.</b> <em>Whoever diligently seeks good seeks favor, but evil comes to him who searches for it</em> — seeking as the determinant of what one finds. Christ's promise: <em>ask, and it will be given to you; seek, and you will find</em> (Matt 7:7). The diligent seeking of good that finds divine favor is the seeking of the kingdom — which is precisely what Christ instructs his disciples to make primary. Those who search for evil find it not because God sends it but because they orient themselves toward it and thus navigate their way into it.</p>",
    "28": "<p><b>Theme.</b> <em>Whoever trusts in his riches will fall, but the righteous will flourish like a green leaf</em> — the wealth-trust collapse vs. the flourishing of the righteous. Christ's Sermon on the Mount addresses the wealth-trust problem directly: <em>you cannot serve God and money</em> (Matt 6:24). The green-leaf flourishing of the righteous is the vine-branch fruitfulness of John 15 — those attached to the true vine bear fruit continuously, their flourishing sourced not in stored resources but in continuous dependence on the life flowing from the vine.</p>",
    "29": "<p><b>Theme.</b> <em>Whoever troubles his own household will inherit the wind, and the fool will be servant to the wise of heart</em> — the household-trouble self-curse. Ephesians 5-6 develops the household-management theology of the NT, grounding it in the Christ-church relationship: those who trouble their households by self-centered authority rather than sacrificial love destroy the very structure they inhabit. The wind-inheritance is the eschatological emptiness of the one who consumed his household rather than nourishing it.</p>",
    "30": "<p><b>Type / Theme.</b> <em>The fruit of the righteous is a tree of life, and whoever captures souls is wise</em> — the tree of life and soul-winning. The tree of life is the eschatological image from Eden (Gen 2:9) restored in Revelation (Rev 22:2) — and Christ is the one through whom access to the tree of life is regained: <em>to the one who conquers I will grant to eat of the tree of life</em> (Rev 2:7). The fruit of the perfectly righteous one is the restoration of the tree of life to those who were barred from it. The <em>laqach nefashot</em> (capturing souls) is the image of the apostolic mission: <em>I will make you fishers of men</em> (Matt 4:19).</p>",
    "31": "<p><b>Theme.</b> <em>If the righteous is repaid on earth, how much more the wicked and the sinner!</em> — the a fortiori argument from the righteous man's earthly experiences of suffering to the certain judgment of the wicked. Peter quotes this verse directly (1 Pet 4:17-18): <em>for it is time for judgment to begin at the household of God; and if it begins with us, what will be the outcome for those who do not obey the gospel of God?</em> The a fortiori logic from Christ's own suffering (the righteous repaid on earth — his cross) to the certain judgment of the unrepentant is precisely the argument Peter inherits from the proverb.</p>"
  },
  "12": {
    "1": "<p><b>Theme.</b> <em>Whoever loves discipline loves knowledge, but he who hates reproof is stupid</em> — love of discipline as love of knowledge. Hebrews applies this to divine discipline: <em>the Lord disciplines the one he loves, and chastises every son whom he receives</em> (Heb 12:6, citing Prov 3:12). The one who loves discipline is the one who has received the son-of-God identity and recognizes the Father's hand in correction. Christ himself <em>learned obedience through what he suffered</em> (Heb 5:8) — the fully human son who underwent discipline as the path to completed perfection.</p>",
    "2": "<p><b>Theme.</b> <em>A good man obtains favor from the LORD, but a man of evil devices he condemns</em> — divine favor for the good man. The man of evil devices who is condemned is the figure of the one who plans wickedness — and ultimately of the devil, the ultimate plotter (<em>the evil one</em> throughout John). Christ is the good man (<em>ish tov</em>) who obtained the Father's maximal favor — not merely approval but resurrection, glory, and the name above every name. Those in him are <em>accepted in the Beloved</em> (Eph 1:6), participating in his standing before the Father.</p>",
    "3": "<p><b>Theme.</b> <em>No one is established by wickedness, but the root of the righteous will never be moved</em> — the established root. Christ uses the tree-and-root imagery: the tree not planted by the Father will be uprooted (Matt 15:13); those planted in him have a root that cannot be moved. The metaphor of being established (confirmed, rooted) in Christ appears in Colossians 2:7 (<em>rooted and built up in him</em>) — the immovable foundation Proverbs assigns to the righteous is identified as Christ himself in the NT (1 Cor 3:11).</p>",
    "4": "<p><b>Type.</b> <em>An excellent wife is the crown of her husband, but she who brings shame is like rottenness in his bones</em> — the crown-wife as the type of the church. Christ's bride, the church, is the one whom he is sanctifying to present to himself <em>in splendor, without spot or wrinkle or any such thing</em> (Eph 5:27). The wife who is her husband's crown — his glory, his highest honor in the community — is the type of the church as the glory of Christ (cf. 1 Cor 11:7 for this glory-relationship). The rottenness that shames anticipates the unfaithful countertype, elaborated in the Prophets' images of the unfaithful bride (Hos 1-3; Ezek 16).</p>",
    "5": "<p><b>Revelation of God.</b> <em>The thoughts of the righteous are just; the counsels of the wicked are deceitful</em> — just thoughts as the interior of the righteous. Christ's diagnosis goes deeper: the thoughts of the heart are the source of all moral action (Matt 15:19). His own thoughts were entirely just — <em>in him is no sin</em> (1 John 3:5) at the level of inner deliberation. The sanctification of thoughts and intentions is what Hebrews identifies as the Spirit's work: <em>the word of God... discerning the thoughts and intentions of the heart</em> (Heb 4:12).</p>",
    "6": "<p><b>Theme.</b> <em>The words of the wicked lie in wait for blood, but the mouth of the upright delivers them</em> — words that ambush vs. words that deliver. Christ's words deliver those who are being ambushed by false teaching, by guilt, by the accuser. His instruction in the synagogue at Nazareth announces his mission: <em>to proclaim liberty to the captives</em> (Luke 4:18, citing Isa 61:1). The mouth of the upright that delivers is the mouth of the one who speaks truth into the situation where ambush has been set.</p>",
    "7": "<p><b>Theme.</b> <em>The wicked are overthrown and are no more, but the house of the righteous will stand</em> — the standing house of the righteous. Matthew 7:24-27 again: the house built on the rock of Christ's words stands when the storm comes; the house built on sand is overthrown. The wicked who are overthrown and are no more is the eschatological pattern — the house of the righteous that stands is the church built on the confession of Christ (Matt 16:18: <em>on this rock I will build my church, and the gates of hell shall not prevail against it</em>).</p>",
    "8": "<p><b>Theme.</b> <em>A man is commended according to his good sense, but one of twisted mind is despised</em> — good sense as the basis of honorable reputation. The <em>sekhel</em> (good sense/wisdom) that produces commendation is the same word used for the wisdom that makes the Servant successful in Isaiah 52:13 (<em>behold, my servant shall act wisely — yaskil</em>). Christ is the Servant whose good sense leads to his exaltation after his humiliation. The commendation according to good sense points to the resurrection-vindication of the one whose wisdom appeared foolish to his contemporaries.</p>",
    "9": "<p><b>Theme.</b> <em>Better to be lowly and have a servant than to play the great man and lack bread</em> — the better-than of honest poverty over pretentious poverty. The incarnation is the maximum expression of this: the Lord of glory became the one who had no place to lay his head (Matt 8:20), who was served by women from their own means (Luke 8:3), and who washed his disciples' feet (John 13:5) — the one who might have played the great one choosing instead the posture of the servant. The honest acknowledgment of dependence is the posture of those who know they live from grace rather than from performance.</p>",
    "10": "<p><b>Revelation of God.</b> <em>Whoever is righteous has regard for the life of his animal, but the mercy of the wicked is cruel</em> — care for animals as an index of righteousness. God's care extends to animals (Ps 104; Matt 6:26; Luke 12:6) — the God who notes the sparrow's fall (Matt 10:29) is the God whose righteous character is reflected in those who care for the creatures under their charge. Christ's shepherd imagery (John 10:11-14) applies the same attentiveness to the sheep that the righteous man applies to his animal — each sheep known by name, each life regarded.</p>",
    "11": "<p><b>Theme.</b> <em>Whoever works his land will have plenty of bread, but he who follows worthless pursuits lacks sense</em> — the work-land-bread connection. The prodigal son squanders everything following worthless pursuits (Luke 15:13 — <em>reckless living</em>) and ends up hungry in a foreign land. His return to the father who has plenty of bread is the parabolic fulfillment of the proverb's reverse: the one who works the father's land has bread; the one who chases emptiness starves. The father's welcome — <em>the fatted calf, rejoicing</em> — is the abundance that waits for the returning worker.</p>",
    "12": "<p><b>Theme.</b> <em>Whoever is wicked covets the spoil of evildoers, but the root of the righteous bears fruit</em> — the rootedness that produces fruit vs. the raiding-for-spoil of the wicked. John 15:5: <em>I am the vine; you are the branches. Whoever abides in me and I in him, he it is that bears much fruit</em>. The root-bearing-fruit is the vine-branch fruitfulness — the continuous production from rootedness in Christ rather than the episodic raiding that characterizes the wicked's approach to resources.</p>",
    "13": "<p><b>Theme.</b> <em>An evil man is ensnared by the transgression of his lips, but the righteous escapes from trouble</em> — the lip-snare and the righteous escape. Christ's trial demonstrates both: his accusers are ensnared by the false charges they bring — their lips produce the testimony that exposes their own injustice. The righteous one escapes through resurrection — not from suffering (which he enters fully) but from the ultimate death that sin produces. The ensnared accusers receive the judgment they attempted to bring on the innocent.</p>",
    "14": "<p><b>Theme.</b> <em>From the fruit of his mouth a man is satisfied with good, and the work of a man's hand comes back to him</em> — mouth-fruit as self-satisfaction and labor's return. Christ's words produce an overflow that returns to those who receive them: <em>the words that I have spoken to you are spirit and life</em> (John 6:63). The work of his hands on the cross comes back to him in resurrection glory — the fruit of his obedience is the harvest of those given him by the Father (John 17:24). The mouth-fruit-satisfaction principle operates at its maximum in the one whose every word is life.</p>",
    "15": "<p><b>Theme.</b> <em>The way of a fool is right in his own eyes, but a wise man listens to advice</em> — self-assessed rightness vs. counseled wisdom. The disciples' repeated misunderstandings and resistance to Jesus' teaching about his death (Matt 16:22-23; Mark 9:31-32) — in each case, the way seemed right in their own eyes until Christ reoriented them. Peter's rebuke of the cross-prediction is met with the sharpest correction in the Gospels: <em>get behind me, Satan, for you are not setting your mind on the things of God, but the things of man</em>. The wise man who listens to advice is the one who submits his own assessment to the Christ who sees further.</p>",
    "16": "<p><b>Theme.</b> <em>The vexation of a fool is known at once, but the prudent man ignores an insult</em> — the prudent ignoring of insult. Christ's silence before Herod's questions (Luke 23:9) and his non-defensive responses to the scribes' trapping questions are the model of this prudence. Peter's instruction for those who suffer unjustly: <em>when he was reviled, he did not revile in return; when he suffered, he did not threaten, but continued entrusting himself to him who judges justly</em> (1 Pet 2:23) — the Christ-pattern is precisely the proverb's prudent ignoring of insult, grounded in trust in divine justice.</p>",
    "17": "<p><b>Type / Direct.</b> <em>Whoever speaks the truth gives honest evidence, but a false witness utters deceit</em> — the truthful witness. Christ is the faithful and true witness (<em>ho martys ho pistos kai alethinos</em>, Rev 3:14; 1:5) — the true witness to the Father's character and will. His testimony at his own trial was the truth that condemned him (Mark 14:62) — the one who spoke truth when a convenient lie would have saved him is the maximum truthful witness. Revelation's use of Christ as the faithful witness grounds the call for the martyrs (also <em>martyroi</em>, witnesses) to speak the truth regardless of cost.</p>",
    "18": "<p><b>Theme.</b> <em>There is one whose rash words are like sword thrusts, but the tongue of the wise brings healing</em> — the healing tongue. Christ's words healed: literally (healing the sick, John 9:6-7; Luke 17:14), and spiritually (<em>your sins are forgiven</em>, Luke 5:20). John 6:63: <em>the words I have spoken to you are spirit and life</em>. The tongue of the wise that brings healing finds its ultimate expression in the Logos whose word of command restored what was broken — <em>be clean</em> (Matt 8:3), <em>arise</em> (Luke 7:14), <em>come forth</em> (John 11:43). Every healing word from Christ is the proverb's healing tongue at its maximum.</p>",
    "19": "<p><b>Revelation of God.</b> <em>Truthful lips endure forever, but a lying tongue is but for a moment</em> — the permanence of truth vs. the momentary duration of the lie. Christ's claim: <em>heaven and earth will pass away, but my words will not pass away</em> (Matt 24:35). The truthful lips that endure forever are fulfilled in the one whose words are eternal — the Logos through whom all things were created and whose speech carries the durability of divine truth. The lying tongue's momentary duration is the wisdom tradition's observation that deception is ultimately unstable and self-dismantling.</p>",
    "20": "<p><b>Theme.</b> <em>Deceit is in the heart of those who devise evil, but those who plan peace have joy</em> — peace-planning as joy-producing. Christ is the Prince of Peace (Isa 9:6) and the one who gives peace not as the world gives (John 14:27). The counselors of peace (<em>yoatzei shalom</em>) whose advice leads to joy are the peaceable ones of the Sermon on the Mount: <em>blessed are the peacemakers, for they shall be called sons of God</em> (Matt 5:9). The joy that belongs to those who plan peace is the beatitude-joy — the kingdom blessing for those whose inner orientation produces shalom.</p>",
    "21": "<p><b>Theme.</b> <em>No ill befalls the righteous, but the wicked are filled with trouble</em> — the righteous's protection from ultimate harm. Christ in John 10:28: <em>I give them eternal life, and they will never perish, and no one will snatch them out of my hand</em>. The <em>no ill befalls</em> is not a promise of earthly immunity (the NT explicitly corrects that reading) but of ultimate preservation — nothing can separate the righteous from the love of God in Christ (Rom 8:38-39). The trouble that fills the wicked is the self-generated consequence of the opposition to the God who is their only refuge.</p>",
    "22": "<p><b>Direct / Revelation of God.</b> <em>Lying lips are an abomination to the LORD, but those who act faithfully are his delight</em> — the divine delight in faithful action. Christ is the one who acts faithfully in every respect — the Father's delight in the Son expressed at baptism and transfiguration is the divine delight in the faithfully-acting one. The abomination of lying lips is demonstrated in Christ's contrast with the devil: <em>he was a murderer from the beginning... when he lies he speaks out of his own character, for he is a liar and the father of lies</em> (John 8:44). The delight-abomination distinction is mapped onto the Christ-devil contrast.</p>",
    "23": "<p><b>Theme.</b> <em>A prudent man conceals knowledge, but the heart of fools proclaims folly</em> — prudent concealment of knowledge. Christ instructed his disciples not to reveal his messianic identity prematurely (Matt 16:20; Mark 8:30) — the knowledge of his identity was concealed until the appointed time of his death and resurrection could make it intelligible. Paul notes that the wisdom of God was <em>hidden for ages</em> until revealed in Christ (1 Cor 2:7; Eph 3:9-10) — the divine economy of concealment-then-revelation is the maximum expression of the prudent man's practice of withholding knowledge until its proper time.</p>",
    "24": "<p><b>Theme.</b> <em>The hand of the diligent will rule, while the slothful will be put to forced labor</em> — diligent rule. Christ's parable of the talents (Matt 25:14-30) enacts this principle: the servants who put their talents to work rule over more; the one who buried his talent and was slothful had his resources taken from him and was cast out. The rule that belongs to the diligent is ultimately the co-reign with Christ that faithful servants inherit: <em>you have been faithful over a little; I will set you over much</em> (Matt 25:21).</p>",
    "25": "<p><b>Revelation of God.</b> <em>Anxiety in a man's heart weighs him down, but a good word makes him glad</em> — the good word as anxiety-cure. Christ's instruction: <em>do not be anxious about your life</em> (Matt 6:25) — and the gospel is exactly the good word that addresses the root of anxiety. <em>Peace I leave with you; my peace I give to you. Let not your hearts be troubled, neither let them be afraid</em> (John 14:27). The good word that makes glad is the announcement of the gospel — the word of the cross as <em>good news</em> (euangelion) is the concentrated form of the anxiety-lifting, gladness-producing word Proverbs identifies as the cure for the weighted heart.</p>",
    "26": "<p><b>Theme.</b> <em>One who is righteous is a guide to his neighbor, but the way of the wicked leads them astray</em> — the righteous man as neighbor-guide. Christ is the shepherd who goes before his sheep and they follow him (John 10:4) — the guide whose own path becomes the path of those he leads. The Good Shepherd who lays down his life for the sheep is the maximum expression of the righteous guide: not merely pointing the direction but personally leading through the danger zone. The wicked who lead others astray are the false shepherds who scatter (Ezek 34; John 10:12-13).</p>",
    "27": "<p><b>Theme.</b> <em>Whoever is slothful will not roast his game, but the diligent man will get precious wealth</em> — the follow-through of the diligent. The parable of the ten virgins (Matt 25:1-13) enacts the follow-through principle: the wise virgins who were prepared with oil had their game roasted; the foolish virgins who failed to carry through with their preparation found the door shut. The precious wealth of the diligent is the inheritance of the kingdom — the eternal life that belongs to those who were found faithful in following through on what they began.</p>",
    "28": "<p><b>Direct / Type.</b> <em>In the path of righteousness is life, and in its pathway there is no death</em> — the path-of-righteousness as deathless life. Christ's declaration: <em>I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live, and everyone who lives and believes in me shall never die</em> (John 11:25-26). The path of righteousness in which there is no death is Christ himself — the Way (John 14:6) in whom those who walk encounter no ultimate death. The proverb is the OT's most direct anticipatory statement of what Christ declares about himself: the righteous path leads to life and the pathway has no death in it.</p>"
  }
}

def main():
    e = load_comm('mkt-christ', 'proverbs')
    merge_comm(e, DATA)
    save_comm('mkt-christ', 'proverbs', e)
    count = sum(len(v) for v in DATA.values())
    print(f'proverbs mkt-christ: wrote {count} verses across ch 10-12')

if __name__ == '__main__':
    main()
